import{select as d3Select}from"d3-selection";import{hsl as d3Hsl}from"d3-color";import{color}from"../utils.mjs";import{builtInEvaluate}from"../evaluate-datum.js";export default function Scatter(i){const u=i.meta.xScale,f=i.meta.yScale;return function(t){t.each(function(r){var t=r.index;const e=color(r,t);var a=builtInEvaluate(i,r);const c=[];for(let r=0;r<a.length;r+=1)for(let t=0;t<a[r].length;t+=1)c.push(a[r][t]);const o=d3Select(this).selectAll(":scope > circle.scatter").data(c);var l="scatter scatter-"+t,t=o.enter().append("circle").attr("class",l);const n=o.merge(t).attr("fill",d3Hsl(e.toString()).brighter(1.5).formatHex()).attr("stroke",e).attr("opacity",.7).attr("r",1).attr("cx",function(t){return u(t[0])}).attr("cy",function(t){return f(t[1])});if(r.attr)for(const s in r.attr){let t=r.attr[s];"class"===s&&(t=l+" "+r.attr[s]),n.attr(s,t)}o.exit().remove()})}}